public void restoreStream(TableDefinition table, String region) {
    String streamArn = table.getStreamArn();
    if (streamArn == null || streamArn.isBlank()) {
        return;
    }

    String label = streamLabelFromArn(streamArn);
    StreamDescription sd = new StreamDescription();
    sd.setStreamArn(streamArn);
    sd.setStreamLabel(label);
    sd.setStreamStatus(table.isStreamEnabled() ? "ENABLED" : "DISABLED");
    sd.setStreamViewType(table.getStreamViewType() != null
            ? table.getStreamViewType() : "NEW_AND_OLD_IMAGES");
    sd.setTableName(table.getTableName());
    sd.setCreationDateTime(creationDateTimeFromLabel(label));
    sd.setStartingSequenceNumber(String.format("%021d", 1));

    streams.put(streamKey(region, table.getTableName()), sd);
    records.computeIfAbsent(streamArn, ignored -> new ConcurrentLinkedDeque<>());
    LOG.infov("Restored stream for table {0} in region {1}: {2}",
            table.getTableName(), region, streamArn);
}

private String streamLabelFromArn(String streamArn) {
    int labelStart = streamArn.lastIndexOf("/stream/");
    return labelStart >= 0 ? streamArn.substring(labelStart + "/stream/".length()) : streamArn;
}

private Instant creationDateTimeFromLabel(String label) {
    try {
        return LocalDateTime.parse(label, STREAM_LABEL_FORMAT).toInstant(ZoneOffset.UTC);
    } catch (DateTimeException e) {
        return Instant.now();
    }
}

